def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        additive = 0.0
        penalty = 0.0
        for j in range(1, 15):
            if j % 5 == 0:
                decay *= 0.85
            if ratio < (0.03 * j):
                score_part = (j ** 1.7) * (1 - ratio)**3 * decay
                if cap % (j+2) == 0:
                    score_part += np.log1p(j * 2)
                else:
                    score_part -= np.sqrt(j) * 0.75
                score += score_part
            else:
                score_part = j * np.exp(-ratio * j * 0.9) * decay / (j+2)
                if (cap + j) % 4 == 0:
                    score_part += np.sin(ratio * j * 1.1)
                else:
                    score_part -= np.cos(ratio * j * 0.9)
                score += score_part
            if j % 3 == 0:
                additive += np.tanh(score / (j + 1)) * 0.8
            elif j % 2 == 0:
                additive -= np.arctan(score / (j + 1)) * 0.5
            else:
                additive += np.sin(score / (j + 1)) * 0.3
            if j % 7 == 0:
                penalty += np.exp(-score / (j + 1)) * 0.2
            else:
                penalty += (score / (j + 1))**0.5 * 0.1
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if residual % k == 0:
                    score += np.log1p(residual) / (k + 0.8) * (1 + 0.1*k)
                else:
                    score -= (residual ** 0.3) / (k + 1.8) * (1 - 0.05*k)
            else:
                score -= abs(residual) * 0.15 * k**1.1
                if abs(residual) > item * 0.5:
                    penalty += abs(residual) * 0.05 * k
        norm_factor = np.log1p(cap + item) + np.sqrt(item + 1)
        final_value = (score + additive - penalty) / (norm_factor + 1e-5)
        if final_value > 0.5:
            priorities[i] = -final_value * np.exp(-ratio * 0.8) * (1 + np.sin(cap * 0.1))
        elif 0 < final_value <= 0.5:
            priorities[i] = -final_value * (np.log1p(cap) + np.sqrt(item)) * np.cos(ratio)
        elif final_value == 0:
            priorities[i] = np.inf
        else:
            priorities[i] = -final_value * np.tanh(cap * 0.05) / (1 + ratio)
    return priorities
